// Script Continued Below
tasker_2_6_400_resetOULevel();

function tasker_2_6_400_resetOULevel(){
	var grOUs = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
	grOUs.addNullQuery('parent');
	grOUs.query();
	while (grOUs.next()){
		recurseLevelFix(grOUs);
	}
}

function recurseLevelFix(grOUs){
	var ouName;
	try {
		ouName = grOUs.getValue("office_name");

		var levelChanged = false;
		var fromLevel = parseInt(grOUs.office_level);
		if(grOUs.parent){
			var grParent = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
			if(grParent.get(grOUs.parent)){
				var parentLevel = parseInt(grParent.office_level);
				if(fromLevel != parentLevel + 1){
					levelChanged = true;
					grOUs.office_level = parentLevel + 1;
				}			
			}
		} else {
			if(parseInt(grOUs.office_level) != 1){
				levelChanged = true;
				grOUs.office_level = 1;
			}
		}

		if(levelChanged){
			// turn off other business rules
			grOUs.setWorkflow(false);
			grOUs.update('Fix Script - Reset OU level for OU (' + grOUs.office_name + ') to Level (' + grOUs.office_level + ')');
			gs.info('Fix Script - Reset OU level for OU (' + grOUs.office_name + ') From Level(' + fromLevel + ') To Level(' + grOUs.office_level + ')');
		}
		var grChildren = new GlideRecord('x_153465_discovert_discover_office_hierarchy');
		grChildren.addQuery('parent',grOUs.getUniqueValue());
		grChildren.query();
		while (grChildren.next()){
			recurseLevelFix(grChildren);
		}
	} catch(e) {
		gs.error("OU Name:" + ouName + " - Error in 'Tasker 2.6.400 Correct OU Levels' - exception: " + e);
	}

}
